const { Manifold, CrossSection, label, setCircularSegments } = api;
setCircularSegments(48);

// =============================================
// PAC-MAN: sphere with wedge mouth cut out
// Centered at x=-14, facing -Y
// =============================================
const PAC_R = 9;
const PAC_X = -14;

const pacSphere = Manifold.sphere(PAC_R, 48).translate([PAC_X, 0, 0]);

// Mouth wedge: triangle in XY plane extruded along Z
// Apex at (PAC_X, 0), opens toward -Y with 35-deg half-angle
const mouthHalfAngle = 35 * Math.PI / 180;
const mouthReach = PAC_R + 2;
const wa = mouthReach * Math.sin(mouthHalfAngle);

const mouthProfile = [
  [PAC_X, 0],
  [PAC_X - wa, -mouthReach],
  [PAC_X + wa, -mouthReach]
];
const mouthCS = CrossSection.ofPolygons([mouthProfile]);
const mouthWedge = Manifold.extrude(mouthCS, PAC_R * 2 + 4)
  .translate([0, 0, -(PAC_R + 2)]);

const pacman = label(pacSphere.subtract(mouthWedge), 'pacman');

// =============================================
// GHOST: capsule body + scalloped feet + eyes + pupils
// Centered at x=+14
// =============================================
const GH_X = 14;
const GH_R = 7.5;
const GH_CYL_H = 8;

// Hemisphere top: sphere centered at [GH_X, 0, GH_R], spans z=0..2*GH_R=0..15
const ghostHemi = Manifold.sphere(GH_R, 48).translate([GH_X, 0, GH_R]);

// Cylinder: from z=-GH_CYL_H to z=GH_R (top at z=7.5, overlaps hemi by 7.5 units)
const ghostCyl = Manifold.cylinder(GH_R + GH_CYL_H, GH_R, GH_R, 48)
  .translate([GH_X, 0, -GH_CYL_H]);

// Scalloped feet: 3 cylinder subtractions from the bottom
const footR = GH_R / 3.2;
const numFeet = 3;
const scallops = [];
for (let i = 0; i < numFeet; i++) {
  const angle = (i / numFeet) * 2 * Math.PI + Math.PI / 2;
  const fx = GH_X + Math.cos(angle) * (GH_R - footR + 0.5);
  const fy = Math.sin(angle) * (GH_R - footR + 0.5);
  const scallop = Manifold.cylinder(4.5, footR, footR, 32)
    .translate([fx, fy, -GH_CYL_H - 0.5]);
  scallops.push(scallop);
}
const ghostBodyBase = ghostHemi.add(ghostCyl).subtract(Manifold.union(scallops));

// Eyes: two spheres protruding from the front (-Y) face of the ghost body
// They sit mostly outside but overlap 0.8 units so they connect to the body
const eyeZ = GH_R * 0.25; // z height (slightly above center)
const eyeOffX = GH_R * 0.38; // horizontal separation
const eyeR = 2.2;
// Surface point on hemisphere/cylinder at the eye position (front face, -Y)
// Cylinder surface at radius GH_R from center, front side at y=-GH_R
// Eye sphere center: place it at y = -(GH_R - 0.8) so it overlaps 0.8 units
const eyeEmbed = -(GH_R - eyeR * 0.5 + 0.5); // mostly protruding, 0.8 unit overlap

const eyeShapeL = Manifold.sphere(eyeR, 24).translate([GH_X - eyeOffX, eyeEmbed, eyeZ]);
const eyeShapeR = Manifold.sphere(eyeR, 24).translate([GH_X + eyeOffX, eyeEmbed, eyeZ]);

// Pupils: smaller spheres on each eye, positioned at eye center level
const pupilR = 0.9;
const pupilShapeL = Manifold.sphere(pupilR, 16)
  .translate([GH_X - eyeOffX, eyeEmbed - eyeR * 0.5, eyeZ]);
const pupilShapeR = Manifold.sphere(pupilR, 16)
  .translate([GH_X + eyeOffX, eyeEmbed - eyeR * 0.5, eyeZ]);

// Build labeled ghost: body + eyes (eyes overlap body, connecting them)
// Pupils overlap eyes, connecting them
const ghostWithEyes = label(ghostBodyBase, 'ghost')
  .add(label(eyeShapeL.add(eyeShapeR), 'eyes'))
  .add(label(pupilShapeL.add(pupilShapeR), 'pupils'));

return pacman.add(ghostWithEyes);
